const health = $('Check Bot Health').first().json;
const overnight = $('Check Overnight Signals').all().map(i => i.json);
const botOk = health.status === 'healthy' || health.ok;
const pendingCount = overnight.length;
const tickers = overnight.map(o => o.symbol).join(', ') || 'none';
const now = new Date().toLocaleString('en-US', { timeZone: 'America/New_York', weekday: 'long', month: 'long', day: 'numeric' });
return [{ json: { now, bot_healthy: botOk, pending_triggers: pendingCount, watching_tickers: tickers, status_emoji: botOk ? '🟢' : '🔴' } }];
